import{_ as s,C as r,o as n,c as l,j as a,a as u,E as o,w as d,am as p}from"./chunks/framework.Ck27G9m2.js";const k=JSON.parse('{"title":"Mise à jour Firmware (DFU)","description":"","frontmatter":{},"headers":[],"relativePath":"fr/examples/dfu.md","filePath":"fr/examples/dfu.md"}'),m={name:"fr/examples/dfu.md"};function c(f,e,h,v,g,q){const i=r("DfuDemo"),t=r("ClientOnly");return n(),l("div",null,[e[0]||(e[0]=a("h1",{id:"mise-a-jour-firmware-dfu",tabindex:"-1"},[u("Mise à jour Firmware (DFU) "),a("a",{class:"header-anchor",href:"#mise-a-jour-firmware-dfu","aria-label":'Permalink to "Mise à jour Firmware (DFU)"'},"​")],-1)),o(t,null,{default:d(()=>[o(i)]),_:1}),e[1]||(e[1]=p('<h2 id="apercu" tabindex="-1">Aperçu <a class="header-anchor" href="#apercu" aria-label="Permalink to &quot;Aperçu&quot;">​</a></h2><p>La mise à jour de firmware (DFU) est le processus de mise à niveau du logiciel interne exécuté sur votre Boks. Cet outil vous permet de le faire directement depuis votre navigateur à l&#39;aide de Web Bluetooth.</p><p>Le processus de mise à jour s&#39;effectue en deux étapes principales :</p><h3 id="etape-1-preparation-passage-en-mode-dfu" tabindex="-1">Étape 1 : Préparation (Passage en mode DFU) <a class="header-anchor" href="#etape-1-preparation-passage-en-mode-dfu" aria-label="Permalink to &quot;Étape 1 : Préparation (Passage en mode DFU)&quot;">​</a></h3><p>Dans son état de fonctionnement normal, la Boks n&#39;accepte pas directement les mises à jour de firmware pour des raisons de sécurité et de stabilité.</p><ol><li>Connectez-vous d&#39;abord à votre Boks via le contrôleur global en bas de l&#39;écran.</li><li>Le contrôleur vérifiera votre version matérielle et le niveau de batterie.</li><li>Si la batterie est saine, cliquez sur <strong>&quot;Passer en mode DFU&quot;</strong>.</li><li>L&#39;application enverra une commande spécifique (écriture de <code>0x01</code> sur la caractéristique <code>8ec90001-f315-4f60-9fb8-838830daea50</code> du service DFU <code>0000fe59-0000-1000-8000-00805f9b34fb</code>).</li><li>Votre Boks va redémarrer. Elle diffusera désormais un nom différent : <code>DfuTarg</code> ou <code>Boks_DFU</code>.</li></ol><h3 id="etape-2-flashage-du-firmware" tabindex="-1">Étape 2 : Flashage du Firmware <a class="header-anchor" href="#etape-2-flashage-du-firmware" aria-label="Permalink to &quot;Étape 2 : Flashage du Firmware&quot;">​</a></h3><p>Une fois votre appareil en mode DFU, l&#39;interface passera automatiquement au panneau de flashage.</p><ol><li>Sélectionnez le fichier firmware <code>.zip</code> fourni pour votre révision matérielle Boks spécifique.</li><li>Cliquez sur <strong>&quot;Démarrer le Flashage&quot;</strong>.</li><li>Le navigateur va négocier avec le bootloader et commencer à transférer les fragments de firmware.</li><li><strong>Ne fermez pas l&#39;onglet et n&#39;éteignez pas votre ordinateur pendant ce processus.</strong></li></ol><p>Une fois le transfert à 100%, la Boks validera le firmware et redémarrera automatiquement sur le nouveau système d&#39;exploitation.</p><hr><h2 id="securite-depannage" tabindex="-1">Sécurité &amp; Dépannage <a class="header-anchor" href="#securite-depannage" aria-label="Permalink to &quot;Sécurité &amp; Dépannage&quot;">​</a></h2><p>Les mises à jour de firmware impliquent la réécriture de la mémoire principale de l&#39;appareil. Bien que le matériel Boks soit conçu pour être résilient, les interruptions peuvent rendre l&#39;appareil temporairement indisponible.</p><h3 id="mises-a-jour-interrompues" tabindex="-1">Mises à jour Interrompues <a class="header-anchor" href="#mises-a-jour-interrompues" aria-label="Permalink to &quot;Mises à jour Interrompues&quot;">​</a></h3><p>Si le processus de mise à jour est interrompu (ex: votre ordinateur se met en veille, l&#39;onglet du navigateur est fermé, ou la connexion Bluetooth est perdue), le comportement dépend de votre version matérielle :</p><ul><li><strong>Boks V3 (nRF52811) :</strong> L&#39;appareil sera <strong>temporairement indisponible</strong> ou &quot;bloqué en mode mise à jour&quot; (<code>DfuTarg</code>). Il ne répondra pas aux commandes normales ni au bouton physique. <strong>Ne paniquez pas.</strong> Pour le restaurer, il suffit de se reconnecter à l&#39;appareil <code>DfuTarg</code> et de réussir à nouveau le processus de flashage complet depuis l&#39;Étape 2.</li><li><strong>Boks V4 (nRF52833) :</strong> Ces appareils gèrent mieux les interruptions. Souvent, il suffit de retirer les piles et de les réinsérer pour restaurer l&#39;appareil à son état de fonctionnement précédent.</li></ul><h3 id="fichiers-de-firmware-invalides" tabindex="-1">Fichiers de Firmware Invalides <a class="header-anchor" href="#fichiers-de-firmware-invalides" aria-label="Permalink to &quot;Fichiers de Firmware Invalides&quot;">​</a></h3><p>Le bootloader refusera de flasher un fichier firmware qui est corrompu ou destiné à une version matérielle différente. Si vous voyez une erreur comme :</p><blockquote><p>&quot;Le fichier de firmware est invalide ou corrompu pour ce modèle.&quot;</p></blockquote><p>ou</p><blockquote><p>&quot;Ce firmware n&#39;est pas compatible avec la version matérielle de votre Boks.&quot;</p></blockquote><p>Veuillez vérifier que vous avez téléchargé le bon fichier <code>.zip</code> pour votre modèle spécifique de Boks (ex: V3 vs V4).</p>',22))])}const _=s(m,[["render",c]]);export{k as __pageData,_ as default};
